import { NextResponse } from "next/server";
type RiskLevel = "baixo" | "medio" | "alto";
type Hit = {
  id: string;
  title: string;
  level: RiskLevel;
  weight: number;
  rationale: string;
  clause_excerpt?: string;
};
function normalize(s: string) {
  return (s || "")
    .replace(/\u0000/g, "")
    .replace(/[ \t]+/g, " ")
    .replace(/\r/g, "\n");
}
function pickExcerpt(text: string, idx: number, len = 260) {
  const start = Math.max(0, idx - Math.floor(len / 3));
  const end = Math.min(text.length, start + len);
  return normalize(text.slice(start, end)).trim();
}
function scoreToRisk(score: number): RiskLevel {
  if (score >= 70) return "alto";
  if (score >= 35) return "medio";
  return "baixo";
}
function safeJson(data: any, status = 200) {
  return NextResponse.json(data, {
    status,
    headers: {
      "Cache-Control": "no-store",
    },
  });
}
async function extractPdf(buffer: Buffer): Promise<string> {
  // pdf-parse em ESM pode vir como { default: fn } ou direto fn
  const mod: any = await import("pdf-parse");
  const pdfParse = mod?.default ?? mod;
  if (typeof pdfParse !== "function") return "";
  try {
    const out = await pdfParse(buffer);
    return normalize(out?.text || "");
  } catch {
    return "";
  }
}
async function extractDocx(buffer: Buffer): Promise<string> {
  try {
    const mammoth: any = await import("mammoth");
    const out = await mammoth.extractRawText({ buffer });
    return normalize(out?.value || "");
  } catch {
    return "";
  }
}
function extractTxt(buffer: Buffer): string {
  try {
    return normalize(buffer.toString("utf8"));
  } catch {
    return "";
  }
}
function runRules(text: string): { hits: Hit[]; score: number; overall_risk: RiskLevel; resumo: string; proximos_passos: string[] } {
  const t = text.toLowerCase();
  const rules: Hit[] = [
    {
      id: "multa-rescisao",
      title: "Multa elevada / assimetria na rescis�o",
      level: "alto",
      weight: 22,
      rationale: "Multas altas ou s� uma parte podendo rescindir aumenta risco financeiro e de travamento do contrato.",
    },
    {
      id: "renovacao-automatica",
      title: "Renova��o autom�tica sem aviso claro",
      level: "medio",
      weight: 14,
      rationale: "Renova��o autom�tica sem janela de cancelamento clara pode gerar cobran�a inesperada.",
    },
    {
      id: "foro",
      title: "Foro distante do seu domic�lio",
      level: "medio",
      weight: 12,
      rationale: "Foro distante encarece defesa e aumenta fric��o em disputa.",
    },
    {
      id: "reajuste-vago",
      title: "Reajuste/pre�o com crit�rio vago",
      level: "medio",
      weight: 12,
      rationale: "Reajuste sem �ndice ou regra objetiva cria risco de aumento imprevis�vel.",
    },
    {
      id: "limitacao-responsabilidade",
      title: "Limita��o forte de responsabilidade do fornecedor",
      level: "medio",
      weight: 12,
      rationale: "Limitar demais a responsabilidade pode deixar voc� sem repara��o em falhas.",
    },
    {
      id: "cessao-dados",
      title: "Uso/cess�o ampla de dados",
      level: "medio",
      weight: 10,
      rationale: "Cl�usulas amplas sobre dados exigem aten��o (LGPD, finalidade, compartilhamento).",
    },
    {
      id: "confidencialidade-assimetrica",
      title: "Confidencialidade assim�trica",
      level: "baixo",
      weight: 8,
      rationale: "Se s� voc� tem deveres, pode haver desequil�brio de risco.",
    },
  ];
  const patterns: Array<{ id: string; regs: RegExp[] }> = [
    { id: "multa-rescisao", regs: [/multa/i, /penalidade/i, /rescis[a�]o/i, /cl[a�]usula penal/i] },
    { id: "renovacao-automatica", regs: [/renova[c�][a�]o autom[a�]tica/i, /prorroga[c�][a�]o autom[a�]tica/i] },
    { id: "foro", regs: [/foro/i, /comarca/i] },
