  score = Math.min(100, score);
  const overall_risk = scoreToRisk(score);
  const resumo =
    text.trim().length === 0
      ? "N�o consegui extrair texto do arquivo. Se for PDF escaneado (imagem), envie uma vers�o pesquis�vel (com OCR) ou cole o texto."
