    "Cheque foro, responsabilidades, garantias e obriga��es p�s-cancelamento.",
    "Se houver dados pessoais: valide finalidade, base legal, reten��o e compartilhamento (LGPD).",
  ];
  return { hits, score, overall_risk, resumo, proximos_passos };
}
export async function POST(req: Request) {
  try {
    const form = await req.formData();
