export type AnalyzeResult = {
  ok: boolean;
  hits: any[];
  extracted_chars?: number;
  error?: string;
};
function scoreResult(r: AnalyzeResult) {
  return (r?.hits?.length ?? 0) * 10 + (r?.extracted_chars ?? 0) / 1000;
}
function compareResults(a: AnalyzeResult, b: AnalyzeResult) {
  const sameHitsCount = (a?.hits?.length ?? 0) === (b?.hits?.length ?? 0);
  const sameOk = a?.ok === b?.ok;
  return sameOk && sameHitsCount;
}
export async function analyzeTwice(payload: any): Promise<{
  best: AnalyzeResult;
  second: AnalyzeResult;
  consistent: boolean;
}> {
  const [r1, r2] = await Promise.all([
    fetch("/api/analyze", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    }).then((r) => r.json()),
    fetch("/api/analyze", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    }).then((r) => r.json()),
  ]);
  const best = scoreResult(r2) > scoreResult(r1) ? r2 : r1;
  const second = best === r1 ? r2 : r1;
  return { best, second, consistent: compareResults(r1, r2) };
}

import * as pdfjsLib from "pdfjs-dist/legacy/build/pdf.mjs";
// evita warning no Node (worker)
(pdfjsLib as any).GlobalWorkerOptions.workerSrc = undefined;
export async function extractPdfText(buffer: Buffer) {
  // PDF real come�a com "%PDF-"
  const header = buffer.subarray(0, 5).toString("utf8");
  if (header !== "%PDF-") {
    return {
      text: "",
      pageCount: 0,
      status: "not_a_pdf" as const,
      reason: "Arquivo n�o parece um PDF v�lido (header ausente).",
      isLikelyScanned: false,
    };
  }
  try {
    const loadingTask = (pdfjsLib as any).getDocument({
      data: buffer,
      stopAtErrors: false,
      verbosity: 0,
    });
    const pdf = await loadingTask.promise;
    const pageCount = pdf.numPages;
    let all = "";
    for (let i = 1; i <= pageCount; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const strings = content.items
        .map((it: any) => (typeof it?.str === "string" ? it.str : ""))
        .filter(Boolean);
      all += strings.join(" ") + "\n";
    }
    const text = all.trim();
    const isLikelyScanned = text.replace(/\s/g, "").length < 80;
    return {
      text,
      pageCount,
      status: "ok" as const,
      reason: "",
      isLikelyScanned,
    };
  } catch (e: any) {
    return {
      text: "",
      pageCount: 0,
      status: "error" as const,
      reason: e?.message ?? String(e),
      isLikelyScanned: false,
    };
  }
}
